class Character{constructor(data){}CharacterModel(position){this.MoveCharacter(position)}MoveCharacter(position){const chtr=this.GetElement(".character");chtr.style.left=`${position.clientX}px`,chtr.style.top=`${position.clientY}px`}IsElementExist(el){let isExist=!1;return isExist=null!=document.querySelector(el),isExist}GetElement(el){return document.querySelector(el)}}export default Character;